#include<bits/stdc++.h>
using namespace std;
int mp[10001];
int n;
struct node{
	int ch,ma,en,id;
}a[10001];
int sum(node x){
	return x.ch+x.ma+x.en;
}
int s2(node x){
	return x.ch+x.ma;
}
int s3(node x){
	return max(x.ch,x.ma);
}
bool cmp(node a,node b){
	int k=sum(a),v=sum(b);
	if(k!=v){
		return k>v;
	}else{
		k=s2(a),v=s2(b);
		if(k!=v)return k>v;
		k=s3(a),v=s3(b);
		if(k!=v)return k>v;
		mp[a.id]=1,mp[b.id]=1;
		return a.id<b.id;
	}
}
int main(){
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;for(register int i=1;i<=n;i++)cin>>a[i].ch>>a[i].ma>>a[i].en,a[i].id=i;
	sort(a+1,n+a+1,cmp);
	int sum1=0;
	mp[0]=1;
	node nw={a[1].ch,a[1].ma,a[1].en,0};
	for(register int i=1;i<=n;i++){
		if(mp[a[i].id]){
			if(sum(a[i])==sum(nw)&&s2(a[i])==s2(nw)&&s3(a[i])==s3(nw))
			mp[a[i].id]=mp[sum1];
			else mp[a[i].id]=i,sum1=a[i].id,nw=a[i];
		}else {
			mp[a[i].id]=i;
			sum1=a[i].id,nw=a[i];	
		}
	}
	for(register int i=1;i<=n;i++)cout<<mp[i]<<endl;
	return 0;
}
